            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "pub fn "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "_from_binary"))), "(s: &mut dyn ReadableStream) -> Result<"), TypeString), ", BinaryError> {"))
            {
                yield return _Line;
            }
            yield return "    let tag = Self::Int_from_binary(s)?;";
            yield return "    if tag == 0 {";
            yield return "        Ok(None)";
            yield return "    } else {";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "        Ok(Some(Self::"), GetEscapedIdentifier(Combine(Combine(Begin(), ElementType.SimpleName(NamespaceName)), "_from_binary"))), "(s)?))"))
