            var ElementType = l.GenericTypeSpec.ParameterValues.Single();
            var ElementSimpleName = ElementType.SimpleName(NamespaceName);
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "pub fn "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "_from_binary"))), "(s: &mut dyn ReadableStream) -> Result<"), TypeString), ", BinaryError> {"))
            {
                yield return _Line;
            }
            yield return "    let length: usize = s.read_size()?.try_into().map_err(|_| binary_error(\"conversion overflow\"))?;";
            if (ElementType.OnTypeRef && ElementType.TypeRef.NameMatches("Byte", "UInt8")) {
                yield return "    " + "s.read_bytes(length)";
            }
            else
            {
                foreach (var _Line in Combine(Combine(Combine(Begin(), "let mut l = "), GetGenericNew(TypeString)), ";"))
                {
                    yield return _Line == "" ? "" : "    " + _Line;
                }
                yield return "    " + "for _ in 0..length";
                yield return "    " + "{";
                foreach (var _Line in Combine(Combine(Combine(Begin(), "    l.push(Self::"), GetEscapedIdentifier(Combine(Combine(Begin(), ElementSimpleName), "_from_binary"))), "(s)?);"))
                {
                    yield return _Line == "" ? "" : "    " + _Line;
                }
                yield return "    " + "}";
                yield return "    " + "Ok(l)";
            }
            yield return "}";
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "pub fn "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "_to_binary"))), "(s: &mut dyn WritableStream, l: &"), TypeString), ") -> Result<(), BinaryError> {"))
            {
                yield return _Line;
            }
            yield return "    s.write_size(l.len().try_into().map_err(|_| binary_error(\"conversion overflow\"))?)?;";
            if (ElementType.OnTypeRef && ElementType.TypeRef.NameMatches("Byte", "UInt8")) {
                yield return "    " + "s.write_bytes(l)?;";
            }
            else
            {
                yield return "    " + "for e in l.iter() {";
                foreach (var _Line in Combine(Combine(Combine(Begin(), "    Self::"), GetEscapedIdentifier(Combine(Combine(Begin(), ElementSimpleName), "_to_binary"))), "(s, e)?;"))
                {
                    yield return _Line == "" ? "" : "    " + _Line;
                }
                yield return "    " + "}";
            }
            yield return "    Ok(())";
            yield return "}";
        }
