        public IEnumerable<String> BinaryTranslator_Map(TypeSpec l, String NamespaceName)
        {
            var gp = l.GenericTypeSpec.ParameterValues;
            if (gp.Count != 2) {
                throw new ArgumentException();
            }
            var SimpleName = l.SimpleName(NamespaceName);
            var TypeString = GetTypeString(l, NamespaceName);
            var KeySimpleName = gp[0].SimpleName(NamespaceName);
            var ValueSimpleName = gp[1].SimpleName(NamespaceName);
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "pub fn "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "_from_binary"))), "(s: &mut dyn ReadableStream) -> Result<"), TypeString), ", BinaryError> {"))
            {
                yield return _Line;
            }
            yield return "    let length: usize = s.read_size()?.try_into().map_err(|_| binary_error(\"conversion overflow\"))?;";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "    let mut l = "), GetGenericNew(TypeString)), ";"))
            {
                yield return _Line;
            }
            yield return "    for _ in 0..length";
            yield return "    {";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "        let key = Self::"), GetEscapedIdentifier(Combine(Combine(Begin(), KeySimpleName), "_from_binary"))), "(s)?;"))
            {
                yield return _Line;
            }
            foreach (var _Line in Combine(Combine(Combine(Begin(), "        let value = Self::"), GetEscapedIdentifier(Combine(Combine(Begin(), ValueSimpleName), "_from_binary"))), "(s)?;"))
            {
                yield return _Line;
            }
            yield return "        l.insert(key, value);";
            yield return "    }";
            yield return "    Ok(l)";
            yield return "}";
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "pub fn "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "_to_binary"))), "(s: &mut dyn WritableStream, l: &"), TypeString), ") -> Result<(), BinaryError> {"))
            {
                yield return _Line;
            }
            yield return "    s.write_size(l.len().try_into().map_err(|_| binary_error(\"conversion overflow\"))?)?;";
            yield return "    for (key, value) in l.iter() {";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "        Self::"), GetEscapedIdentifier(Combine(Combine(Begin(), KeySimpleName), "_to_binary"))), "(s, key)?;"))
            {
                yield return _Line;
            }
            foreach (var _Line in Combine(Combine(Combine(Begin(), "        Self::"), GetEscapedIdentifier(Combine(Combine(Begin(), ValueSimpleName), "_to_binary"))), "(s, value)?;"))
            {
                yield return _Line;
            }
            yield return "    }";
            yield return "    Ok(())";
            yield return "}";
        }
